#!/bin/bash
set -e
cd /workspaces/Purgatoire
python3 - << 'PYEOF2'
import base64,os
data={
    "pages/builder.html":"",
    "assets/data/builder_data.json":"",
}
for p,b in data.items():
    os.makedirs(os.path.dirname(p),exist_ok=True)
    open(p,"wb").write(base64.b64decode(b))
print("✅ OK")
PYEOF2
git add pages/builder.html assets/data/builder_data.json
git commit -m "fix: builder complet - images listes, filtrage costumes, artwork portrait, type arme, maitrises"
git push
echo "🚀 Done"
